#include <iostream>
#include <iomanip>

class BankAccount {
private:
    double balance;

public:
    BankAccount(double initialBalance = 0.0) : balance(initialBalance) {}

    void deposit(double amount) {
        if (amount > 0) {
            balance += amount;
        }
    }

    void withdraw(double amount) {
        if (amount > 0 && balance >= amount) {
            balance -= amount;
        }
    }

    double getBalance() const {
        return balance;
    }
};

int main() {
    std::cout << std::fixed << std::setprecision(1);

    BankAccount acc1(100.0);
    acc1.deposit(50.0);
    acc1.withdraw(30.0);
    std::cout << acc1.getBalance() << std::endl;

    BankAccount acc2(0.0);
    acc2.withdraw(10.0);
    std::cout << acc2.getBalance() << std::endl;

    BankAccount acc3(200.0);
    acc3.deposit(-10.0);
    acc3.withdraw(50.0);
    std::cout << acc3.getBalance() << std::endl;

    BankAccount acc4(100.0);
    acc4.withdraw(-20.0);
    std::cout << acc4.getBalance() << std::endl;

    return 0;
}
